var DEFAULT_OUTPUT_FILE = "index.html";
function resolveOutFile(input) {
  const outFile = getOptionString(
    input.options,
    "outFile",
    DEFAULT_OUTPUT_FILE
  );
  const trimmedOutFile = outFile.trim();
  const finalOutFile = trimmedOutFile.length > 0 ? trimmedOutFile : DEFAULT_OUTPUT_FILE;
  assert(
    finalOutFile.endsWith(".html"),
    `Invalid outFile "${finalOutFile}". The output file must end with .html`
  );
  return finalOutFile;
}
